<?php // blog.php session_start(); require_once 'database.php'; $database = new Database(); $conn = $database->getConnection(); require_once __DIR__. '/blog-setup.php'; ensureBlogTables($conn); seedBlogData($conn); // Get blog posts $limit = 10; $page = isset($_GET['page'])? (int)$_GET['page']: 1; $category = isset($_GET['category'])? $_GET['category']: null; $search = isset($_GET['search'])? $_GET['search']: null; $offset = ($page - 1) * $limit; // Fetch featured post $featuredSql = "SELECT * FROM blog_posts WHERE status = 'published' AND is_featured = 1 ORDER BY publish_date DESC LIMIT 1"; $featuredStmt = $conn->prepare($featuredSql); $featuredStmt->execute; $featuredPost = $featuredStmt->fetch(); if (!$featuredPost) { $fallbackSql = "SELECT * FROM blog_posts WHERE status = 'published' ORDER BY publish_date DESC LIMIT 1"; $fallbackStmt = $conn->prepare($fallbackSql); $fallbackStmt->execute; $featuredPost = $fallbackStmt->fetch(); } // Fetch recent posts $postsSql = "SELECT * FROM blog_posts WHERE status = 'published' AND (id!=:featured_id OR:featured_id_check IS NULL)"; $featuredIdValue = $featuredPost? $featuredPost['id']: null; $postsParams = [ ':featured_id' => $featuredIdValue, ':featured_id_check' => $featuredIdValue ]; if ($category) { $postsSql.= " AND category =:category"; $postsParams[':category'] = $category; } if ($search) { $postsSql.= " AND (title LIKE:search OR excerpt LIKE:search OR content LIKE:search)"; $postsParams[':search'] = "%$search%"; } $postsSql.= " ORDER BY publish_date DESC LIMIT:limit OFFSET:offset"; $postsStmt = $conn->prepare($postsSql); foreach ($postsParams as $key => $value) { $postsStmt->bindValue($key, $value); } $postsStmt->bindValue(':limit', $limit, PDO::PARAM_INT); $postsStmt->bindValue(':offset', $offset, PDO::PARAM_INT); $postsStmt->execute; $posts = $postsStmt->fetchAll(); // Get categories $categoriesSql = "SELECT * FROM blog_categories ORDER BY name"; $categoriesStmt = $conn->prepare($categoriesSql); $categoriesStmt->execute; $categories = $categoriesStmt->fetchAll(); // Get recent posts for sidebar $recentSql = "SELECT id, title, publish_date, featured_image FROM blog_posts WHERE status = 'published' ORDER BY publish_date DESC LIMIT 5"; $recentStmt = $conn->prepare($recentSql); $recentStmt->execute; $recentPosts = $recentStmt->fetchAll(); // Get total count for pagination $countSql = "SELECT COUNT(*) as total FROM blog_posts WHERE status = 'published'"; if ($category) { $countSql.= " AND category =:category"; } $countStmt = $conn->prepare($countSql); if ($category) { $countStmt->bindValue(':category', $category); } $countStmt->execute; $totalPosts = $countStmt->fetch['total']; $totalPages = ceil($totalPosts / $limit);?> <!DOCTYPE html>
