.newsletter-btn:hover { background: var(--primary); transform: translateY(-3px); }.tags-cloud { display: flex; flex-wrap: wrap; gap: 10px; }.tag { background: var(--gray); padding: 8px 15px; border-radius: 20px; font-size: 0.9rem; color: #555; text-decoration: none; transition: all 0.3s ease; }.tag:hover { background: var(--primary); color: white; }.blog-cta { background: linear-gradient(rgba(0,0,0,0.7), rgba(0,0,0,0.7)), url('/images/CCTV-command-centre.jpg'); background-size: cover; background-position: center; padding: 80px 5%; text-align: center; color: white; margin-top: 80px; border-radius: 20px; }.blog-cta h2 { font-size: 2.5rem; margin-bottom: 20px; }.blog-cta p { font-size: 1.2rem; max-width: 700px; margin: 0 auto 30px; opacity: 0.9; }.blog-cta.hero-buttons { justify-content: center; flex-wrap: wrap; } /* Responsive Blog Layout */ @media (max-width: 992px) {.blog-container { grid-template-columns: 1fr; gap: 40px; }.featured-post { margin-bottom: 40px; }.blog-hero h1 { font-size: 2.8rem; }.featured-content h2 { font-size: 1.8rem; } } @media (max-width: 768px) {.blog-hero h1 { font-size: 2.3rem; }.blog-posts-grid { grid-template-columns: 1fr; }.featured-image { height: 300px; }.featured-content { padding: 30px; }.blog-hero p { font-size: 1.1rem; }.blog-cta h2 { font-size: 2rem; }.blog-hero { height: auto; padding: 70px 5% 50px; margin-top: 100px; }.blog-main { padding: 60px 5% 70px; }.blog-container { gap: 32px; }.sidebar-widget { padding: 24px; }.blog-search-input { padding: 16px 20px 16px 48px; font-size: 1rem; } } @media (max-width: 480px) {.featured-content h2 { font-size: 1.5rem; }.post-meta { flex-wrap: wrap; }.blog-hero h1 { font-size: 2rem; }.blog-cta h2 { font-size: 1.8rem; }.blog-hero { margin-top: 90px; padding: 60px 6% 45px; }.blog-search { margin-top: 20px; }.featured-content { padding: 24px; }.post-card-content { padding: 20px; }.post-image { height: 200px; } } @keyframes rotate { 0% { transform: rotate(0deg); } 100% { transform: rotate(360deg); } } @keyframes fadeIn { from { opacity: 0; transform: translateY(20px); } to { opacity: 1; transform: translateY(0); } } </style> <script src="/assets/js/darkmode-unified.js" defer></script></head> <body> <?php include __DIR__. '/components/tracking-noscript.html';?> <?php include __DIR__. '/components/header.php';?> <?php include __DIR__. '/components/mobile-nav.php';?> <main id="main-content" role="main"> <?php include __DIR__. '/pages/blog-content.php';?> </main> <?php include __DIR__. '/components/footer.html';?> </body> </html> 




